// // This JK flip-flop design inverts the behavior of the standard specification. It toggles Q when J=0 and K=0, resets Q to 1 when J=0 and K=1, sets Q to 0 when J=1 and K=0, and leaves Q unchanged when both J and K are 1.
module top_module(
	input J, K, Clk,
	output reg Q,
	output Q_b
    );assign Q_b = ~Q;

	always @ (posedge Clk)

	case ({J,K})
		2'b00: Q <= Q;
		2'b01: Q <= 1'b0;
		2'b10: Q <= 1'b1;
		2'b11: Q <= !Q;
	endcase

endmodule
